/**
 * Well Test Analysis Studio - engine validation harness (WT1).
 *
 * Standalone gate runner modeled on tools/validation/mbal-validation.ts:
 * labeled CASES, per-check tolerances stated inline, exit 0 only on full
 * pass. Run from the repo root:
 *
 *   node tools/validation/welltest/run-validation.mjs
 *
 * Prerequisite: goldens generated by the independent Python oracle
 * (python3 tools/validation/welltest/genfixtures.py), committed at
 * src/utils/welltest/__tests__/goldens.json.
 *
 * CASE 1  Stehfest inversion against known transform pairs
 * CASE 2  Bessel / E1 / line source vs the integral-based Python oracle
 * CASE 3  Analytic identity gates (exact literature truths):
 *           pwD -> tD/CD early, 0.5(ln tD + 0.80907) + S late,
 *           Bourdet derivative plateau 0.5
 * CASE 4  Homogeneous pwD(tD) vs oracle goldens across storage/skin cases
 * CASE 5  Drawdown fixture round trip (MDH + auto-fit recover k, s, C)
 * CASE 6  Buildup fixture round trip (Horner + auto-fit recover k, s, C, p*)
 * CASE 7  Published literature fixtures (Lee / Ahmed-Earlougher) - armed only when
 *           book-verified data is present in literature-fixtures.json;
 *           WT2 merges only after this case is armed and green.
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

import {
  besselI0, besselI1, besselK0e, besselK1e, expE1, stehfestInvert,
} from '../../../src/utils/welltest/numerics.js';
import {
  pwdHomogeneous, lineSourcePd, radialSemilogPwd,
} from '../../../src/utils/welltest/models/homogeneous.js';
import {
  getModel, toDimensionlessGroups, evaluateDrawdown, evaluateBuildup,
} from '../../../src/utils/welltest/models/modelCatalog.js';
import { bourdetDerivative } from '../../../src/utils/welltest/derivative.js';
import { mdhAnalysis, hornerAnalysis } from '../../../src/utils/welltest/analysis.js';
import { autoFitModel } from '../../../src/utils/welltest/autoFit.js';

const here = path.dirname(fileURLToPath(import.meta.url));
const goldens = JSON.parse(
  fs.readFileSync(path.join(here, '../../../src/utils/welltest/__tests__/goldens.json'), 'utf8')
);

let passed = 0;
let failed = 0;

const check = (name, actual, expected, relTol, unit = '') => {
  const err = Math.abs(actual - expected) / Math.max(Math.abs(expected), 1e-300);
  const ok = Number.isFinite(actual) && err <= relTol;
  const detail = `${actual}${unit ? ` ${unit}` : ''} vs ${expected}${unit ? ` ${unit}` : ''} (rel err ${err.toExponential(2)}, tol ${relTol})`;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}: ${detail}`);
  if (ok) passed += 1; else failed += 1;
};

const checkAbs = (name, actual, expected, absTol, unit = '') => {
  const err = Math.abs(actual - expected);
  const ok = Number.isFinite(actual) && err <= absTol;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}: ${actual}${unit ? ` ${unit}` : ''} vs ${expected}${unit ? ` ${unit}` : ''} (abs err ${err.toExponential(2)}, tol ${absTol})`);
  if (ok) passed += 1; else failed += 1;
};

const banner = (title) => console.log(`\n=== ${title} ===`);

// ---------------------------------------------------------------------------
banner('CASE 1: Stehfest inversion vs known transform pairs');
check('L^-1{1/s}(3.7) = 1', stehfestInvert((s) => 1 / s, 3.7), 1, 1e-8);
check('L^-1{1/s^2}(2.5) = t', stehfestInvert((s) => 1 / (s * s), 2.5), 2.5, 1e-5);
check('L^-1{1/(s+2)}(0.5) = e^-1', stehfestInvert((s) => 1 / (s + 2), 0.5), Math.exp(-1), 1e-4);
check('L^-1{1/sqrt(s)}(2) = 1/sqrt(pi t)', stehfestInvert((s) => 1 / Math.sqrt(s), 2), 1 / Math.sqrt(2 * Math.PI), 1e-4);

// ---------------------------------------------------------------------------
banner('CASE 2: special functions vs independent Python oracle');
{
  let worst = { name: '', err: 0 };
  for (const row of goldens.bessel) {
    for (const [name, fn, truth] of [
      ['I0', besselI0, row.i0], ['I1', besselI1, row.i1],
      ['K0e', besselK0e, row.k0e], ['K1e', besselK1e, row.k1e],
    ]) {
      const err = Math.abs(fn(row.x) - truth) / Math.abs(truth);
      if (err > worst.err) worst = { name: `${name}(${row.x})`, err };
    }
  }
  console.log(`        (${goldens.bessel.length * 4} values compared, worst ${worst.name} rel err ${worst.err.toExponential(2)}; gate 2e-6)`);
  if (worst.err > 2e-6) { failed += 1; console.log('  FAIL  Bessel gate 2e-6 exceeded'); } else { passed += 1; console.log('  PASS  Bessel gate 2e-6'); }
}
for (const row of goldens.e1) check(`E1(${row.x})`, expE1(row.x), row.e1, 1e-12);
for (const row of goldens.lineSource) check(`line source pD(tD=${row.tD})`, lineSourcePd(row.tD), row.pD, 1e-10);

// ---------------------------------------------------------------------------
banner('CASE 3: analytic identity gates (exact literature truths)');
check('early-time storage unit slope: pwD(tD=1, CD=1000) = tD/CD', pwdHomogeneous(1, { skin: 0, cd: 1000 }), 1e-3, 0.02);
check('radial semilog: pwD(tD=1e6) = 0.5(ln tD + 0.80907)', pwdHomogeneous(1e6, { skin: 0, cd: 0 }), radialSemilogPwd(1e6), 5e-3);
checkAbs('skin additivity at tD=1e4', pwdHomogeneous(1e4, { skin: 5, cd: 0 }) - pwdHomogeneous(1e4, { skin: 0, cd: 0 }), 5, 0.01);
{
  const tDs = Array.from({ length: 41 }, (_, i) => Math.pow(10, 5 + (2 * i) / 40));
  const series = tDs.map((tD) => ({ x: tD, y: pwdHomogeneous(tD, { skin: 3, cd: 100 }) }));
  const deriv = bourdetDerivative(series, { L: 0.1 });
  const mid = deriv[Math.floor(deriv.length / 2)];
  check('Bourdet derivative radial plateau = 0.5', mid.derivative, 0.5, 0.01);
}

// ---------------------------------------------------------------------------
banner('CASE 4: homogeneous pwD vs oracle goldens (35 points, 5 storage/skin cases)');
{
  let worst = { err: 0, row: null };
  for (const row of goldens.pwd) {
    const err = Math.abs(pwdHomogeneous(row.tD, { skin: row.skin, cd: row.cd }) - row.pwd) / Math.abs(row.pwd);
    if (err > worst.err) worst = { err, row };
  }
  console.log(`        worst: skin=${worst.row.skin} CD=${worst.row.cd} tD=${worst.row.tD.toExponential(1)} rel err ${worst.err.toExponential(2)}`);
  if (worst.err > 5e-3) { failed += 1; console.log('  FAIL  pwD gate 5e-3 exceeded'); } else { passed += 1; console.log('  PASS  pwD gate 5e-3'); }
}

// ---------------------------------------------------------------------------
banner('CASE 5: drawdown fixture round trip (truth k=85 md, s=6.5, C=0.015 bbl/psi)');
{
  const model = getModel('homogeneous');
  const { reservoir, truth, points } = goldens.fixtures.drawdown;
  const groups = toDimensionlessGroups({ ...reservoir, k: truth.k });
  const forward = evaluateDrawdown({ model, params: truth, reservoir, times: points.map((p) => p.t) });
  check('forward model reproduces oracle fixture (mid point)', forward[22].dp, points[22].dp, 1e-5, 'psi');

  const tOut = ((60 + 3.5 * truth.skin) * truth.C * groups.cdPerBblPsi) / groups.tdPerHour;
  const mdh = mdhAnalysis({ points: points.filter((p) => p.t > 8 * tOut).map((p) => ({ t: p.t, pwf: p.pwf })), ...reservoir });
  check('MDH permeability', mdh.k, truth.k, 0.02, 'md');
  checkAbs('MDH skin', mdh.skin, truth.skin, 0.3);

  const fit = autoFitModel({ model, testType: 'drawdown', data: points.map((p) => ({ t: p.t, dp: p.dp })), reservoir, initialParams: { k: 20, skin: 0, C: 0.003 } });
  check('auto-fit permeability', fit.params.k, truth.k, 0.01, 'md');
  checkAbs('auto-fit skin', fit.params.skin, truth.skin, 0.2);
  check('auto-fit wellbore storage', fit.params.C, truth.C, 0.05, 'bbl/psi');
}

// ---------------------------------------------------------------------------
banner('CASE 6: buildup fixture round trip (tp=36 hr, exact superposition)');
{
  const model = getModel('homogeneous');
  const { reservoir, truth, tp, points, pwfShutIn } = goldens.fixtures.buildup;
  const groups = toDimensionlessGroups({ ...reservoir, k: truth.k });
  const forward = evaluateBuildup({ model, params: truth, reservoir, tp, dts: points.map((p) => p.dt) });
  check('forward pwf at shut-in matches oracle', forward.pwfAtShutIn, pwfShutIn, 1e-6, 'psi');

  const tOut = ((60 + 3.5 * truth.skin) * truth.C * groups.cdPerBblPsi) / groups.tdPerHour;
  const horner = hornerAnalysis({ points: points.filter((p) => p.dt > 8 * tOut && p.dt < tp).map((p) => ({ dt: p.dt, pws: p.pws })), tp, pwfShutIn, ...reservoir });
  check('Horner permeability', horner.k, truth.k, 0.03, 'md');
  checkAbs('Horner skin', horner.skin, truth.skin, 0.5);
  checkAbs('Horner p* (infinite acting -> pi)', horner.pStar, reservoir.pi, 5, 'psi');

  const fit = autoFitModel({ model, testType: 'buildup', data: points.map((p) => ({ dt: p.dt, dp: p.dp })), reservoir, tp, initialParams: { k: 300, skin: 0, C: 0.002 } });
  check('auto-fit permeability', fit.params.k, truth.k, 0.01, 'md');
  checkAbs('auto-fit skin', fit.params.skin, truth.skin, 0.2);
  check('auto-fit wellbore storage', fit.params.C, truth.C, 0.05, 'bbl/psi');
}

// ---------------------------------------------------------------------------
banner('CASE 7: published literature fixtures (Lee / Ahmed-Earlougher)');
{
  const litPath = path.join(here, 'literature-fixtures.json');
  if (!fs.existsSync(litPath)) {
    console.log('  SKIP  literature-fixtures.json not present.');
    console.log('        Fixture input data must be typed from the book (never recalled)');
    console.log('        and committed here with citations. WT2 merges only after this');
    console.log('        case is armed and green (hard gate, see WellTestAnalysisStudio-PLAN.md).');
  } else {
    const lit = JSON.parse(fs.readFileSync(litPath, 'utf8'));
    for (const fixture of lit.buildups || []) {
      // Restrict to the book's straight-line (mid-time) window when the fixture
      // declares one; the full published table stays in the file verbatim.
      const mtr = fixture.mtr || {};
      const points = fixture.points.filter(
        (p) => p.dt >= (mtr.dtMin ?? 0) && p.dt <= (mtr.dtMax ?? Infinity)
      );
      const result = hornerAnalysis({
        points, tp: fixture.tp, pwfShutIn: fixture.pwfShutIn, ...fixture.reservoir,
      });
      check(`${fixture.citation}: permeability`, result.k, fixture.expected.k, fixture.tolerances?.k ?? 0.05, 'md');
      if (fixture.expected.skin !== undefined) {
        checkAbs(`${fixture.citation}: skin`, result.skin, fixture.expected.skin, fixture.tolerances?.skin ?? 0.5);
      }
      if (fixture.expected.m !== undefined) {
        check(`${fixture.citation}: semilog slope m`, result.m, fixture.expected.m, fixture.tolerances?.m ?? 0.05, 'psi/cycle');
      }
      if (fixture.expected.p1hr !== undefined) {
        checkAbs(`${fixture.citation}: p1hr`, result.p1hr, fixture.expected.p1hr, fixture.tolerances?.p1hr ?? 5, 'psi');
      }
      if (fixture.expected.pStar !== undefined) {
        checkAbs(`${fixture.citation}: p*`, result.pStar, fixture.expected.pStar, fixture.tolerances?.pStar ?? 10, 'psi');
      }
    }
  }
}

// ---------------------------------------------------------------------------
console.log(`\n${'='.repeat(50)}`);
console.log(`TOTAL: ${passed} passed, ${failed} failed`);
process.exit(failed === 0 ? 0 : 1);
